mapper.select:
SELECT

FROM
    sys_firmware
WHERE
    1 = 1
    AND firmwareName LIKE CONCAT('%', #{firmwareName}, '%')
    AND chipModelName = #{chipModelName}
    AND deviceType = #{deviceType}
    AND version = #{version}
    AND isDefault = #{isDefault}
    AND userId = #{userId}
ORDER BY createTime DESC

mapper.update:
UPDATE sys_firmware
firmwareName = #{firmwareName}, version = #{version}, chipModelName = #{chipModelName}, deviceType = #{deviceType}, url = #{url}, fileSize = #{fileSize}, fileHash = #{fileHash}, description = #{description}, isDefault = #{isDefault},
WHERE firmwareId = #{firmwareId}

